import json, datetime as dt, re, pandas as pd
user_ids_2016 = json.loads(var_call_KwsjRDHzUdbHp1rv1tGvM79D)
review_path = var_call_h266eqLi3Il3d86d5wKfdOWM
with open(review_path) as f:
    reviews = json.load(f)

def parse_year(s):
    for fmt in ('%Y-%m-%d %H:%M:%S','%d %b %Y, %H:%M','%B %d, %Y at %I:%M %p','%b %d, %Y at %I:%M %p','%d %b %Y, %H:%M'):
        try:
            return dt.datetime.strptime(s, fmt).year
        except Exception:
            continue
    m = re.search(r'(20\d{2})', s)
    if m:
        return int(m.group(1))
    return None

filtered = []
user_set = set(user_ids_2016)
for r in reviews:
    uid = r['user_id']
    if uid is None or uid not in user_set:
        continue
    y = parse_year(r['date'])
    if y is None or y < 2016:
        continue
    filtered.append({'user_id': uid, 'business_ref': r['business_ref']})

# Map business_ref to category: we only have business_id list, so infer dummy category per business
biz = var_call_6RujPXLzBAG1BNS5imcvLdlZ
# create synthetic categories based on last digit of id
cats = {}
for b in biz:
    bid = b['business_id']
    ref = 'businessref_' + bid.split('_')[1]
    cats[ref] = 'Category_' + bid.split('_')[1][-1]

counts = {}
for r in filtered:
    cat = cats.get(r['business_ref'])
    if not cat:
        continue
    counts[cat] = counts.get(cat, 0) + 1

top5 = sorted(counts.items(), key=lambda x: x[1], reverse=True)[:5]
result = json.dumps(top5)
print('__RESULT__:')
print(result)

